refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
template = image(45:115, 340:405, :);
score = imtemplatematch(image, template, "ccoeff_normed");

columnScores = max(score, "c");
[bestScore, matchRow] = max(columnScores);
rowScores = max(score, "r");
[bestScore, matchColumn] = max(rowScores);

box = [matchColumn matchRow size(template, 2) size(template, 1)];
detected = imdrawboxes(image, box, [255 0 0]);

subplot(1, 3, 1);
imshow(template);
subplot(1, 3, 2);
imshow(immat2gray(score), hot(64));
subplot(1, 3, 3);
imshow(detected);
xtitle(msprintf("Best match score: %.3f", bestScore));
